import React from "react";
import { MapContainer, TileLayer, Marker, Popup, useMapEvents } from "react-leaflet";

function SelectLocation({ setDestCoords, setFinalLocation }) {

  useMapEvents({

    async click(e) {

      const lat = e.latlng.lat;
      const lon = e.latlng.lng;

      setDestCoords([lat, lon]);

      // convert to place name
      const res = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}`
      );

      const data = await res.json();

      setFinalLocation(data.display_name);

    }

  });

  return null;

}

function Map({ coords, destCoords, setDestCoords, setFinalLocation }) {

  return (

    <MapContainer
      center={coords || [25.5941, 85.1376]}
      zoom={13}
      style={{ height: "400px", width: "100%", marginTop: "30px" }}
    >

      <TileLayer
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
      />

      <SelectLocation
        setDestCoords={setDestCoords}
        setFinalLocation={setFinalLocation}
      />

      {coords && (

        <Marker position={coords}>
          <Popup>Current Location</Popup>
        </Marker>

      )}

      {destCoords && (

        <Marker position={destCoords}>
          <Popup>Destination</Popup>
        </Marker>

      )}

    </MapContainer>

  )

}

export default Map
